# Normalize per-model SHAP scores so each model's values sum to 1
normalized_shap_scores = {}
for model_name, feature_scores in shap_scores.items():
    # Use absolute values to avoid negatives affecting the distribution (if any)
    total = sum(abs(float(v)) for v in feature_scores.values())
    if total == 0:
        normalized_shap_scores[model_name] = {k: 0.0 for k in feature_scores}
    else:
        normalized_shap_scores[model_name] = {k: abs(float(v)) / total for k, v in feature_scores.items()}

# Write normalized JSON to file and print it
out_path = "normalized_shap_scores.json"
with open(out_path, "w") as f:
    json.dump(normalized_shap_scores, f, indent=2)

print(json.dumps(normalized_shap_scores, indent=2))

